import re

from playwright.sync_api import Page, expect


def test_toolbox_tc002_add_to_cart(page: Page):
    """User can add product to cart"""
    # Step 1: navigate to https://practicesoftwaretesting.com/category/hand-tools
    page.goto("https://practicesoftwaretesting.com/category/hand-tools", wait_until="domcontentloaded")

    # Step 2: click (product-)
    page.locator('[data-testid^="product-"]').nth(0).click()

    # Step 3: click (Add to cart)
    page.get_by_role("button", name="Add to cart").click()

    # Step 4: click (nav-cart)
    page.get_by_test_id("nav-cart").click()

    # Assertions
    # Assertion 1: url_contains
    expect(page).to_have_url(re.compile(r".*https://practicesoftwaretesting\\.com/checkout.*"))
